public abstract class BookingState
{
    public abstract void EnterState(BookingContext booking);
    public abstract void Cancel(BookingContext booking);
    public abstract void DatePassed(BookingContext booking);
    public abstract void EnterDetails(
        BookingContext booking,
        string attendee,
        int ticketCount);
}

public sealed class BookingContext
{
    private BookingState currentState;

    public string Attendee { get; set; } = string.Empty;
    public int TicketCount { get; set; }
    public int BookingId { get; set; }

    public BookingContext()
    {
        TransitionToState(new NewState());
    }

    public void TransitionToState(BookingState state)
    {
        currentState = state;
        currentState.EnterState(this);
    }

    public void SubmitDetails(string attendee, int ticketCount)
    {
        currentState.EnterDetails(this, attendee, ticketCount);
    }

    public void Cancel()
    {
        currentState.Cancel(this);
    }

    public void DatePassed()
    {
        currentState.DatePassed(this);
    }
}

public sealed class NewState : BookingState
{
    public override void EnterState(BookingContext booking)
    {
        booking.BookingId = Random.Shared.Next(1000, 9999);
        Console.WriteLine($"Booking {booking.BookingId} is New");
    }

    public override void EnterDetails(
        BookingContext booking,
        string attendee,
        int ticketCount)
    {
        booking.Attendee = attendee;
        booking.TicketCount = ticketCount;
        booking.TransitionToState(new PendingState());
    }

    public override void Cancel(BookingContext booking)
    {
        booking.TransitionToState(new ClosedState("Booking canceled"));
    }

    public override void DatePassed(BookingContext booking)
    {
        booking.TransitionToState(new ClosedState("Booking expired"));
    }
}

public sealed class PendingState : BookingState
{
    private readonly CancellationTokenSource cancelToken = new();

    public override void EnterState(BookingContext booking)
    {
        Console.WriteLine("Booking is Pending");

        _ = ProcessAsync(booking);
    }

    private async Task ProcessAsync(BookingContext booking)
    {
        await Task.Delay(1000, cancelToken.Token);

        bool success = DateTime.UtcNow.Second % 2 == 0;

        if (success)
        {
            booking.TransitionToState(new BookedState());
        }
        else
        {
            booking.TransitionToState(new NewState());
        }
    }

    public override void Cancel(BookingContext booking)
    {
        cancelToken.Cancel();
        booking.TransitionToState(new ClosedState("Processing canceled"));
    }

    public override void DatePassed(BookingContext booking)
    {
        // Ignore or show a validation message.
    }

    public override void EnterDetails(
        BookingContext booking,
        string attendee,
        int ticketCount)
    {
        // Already processing.
    }
}

